INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00230', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「『君子之交淡如水』，但是君子之交不能永遠是水，『道義』能變水為 酒，只要道義的精神久而不懈，始終如一。『小人之交』以酒開始，但是 雙方都沒有足夠的酒精滿足對方，喝到中途，只好摻水。酒精愈少，清水 愈多。君子之交（我們換一個說法好不好：成功的友誼）先水後酒，情味 愈來愈濃；失敗的友誼以酒始，以水終，情味愈來愈淡。與人相處，先敬 清水。酒，尤其是好酒，最後再拿出來。」根據上文，下列選項何者錯誤？', '["君子淡以親，小人甘以絕", "君子之交，以道義為原則", "友誼應平淡而綿長，才能愈來愈有情味", "君子的友誼，始終都應如美酒般的濃醇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00231', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「沒有哪個器官是像皮膚這樣，同時扮演如此多重的生理與社會角色。它 是抵禦外界的屏障，每天承受無數次的抓扒揉捏，卻不容易破裂。皮膚是 一面螢幕，能即時反映內心的活動，無論是一陣臉紅、冒冷汗或臉上的表 情，都將我們的情緒展露無遺。它也是一本可供瀏覽的書，皮膚的顏色或 狀態，刺在上面的圖騰或疤痕，都向我們訴說著血淋淋的歷史，或是每個 生命獨有的故事。」根據上文，最不符合文意的選項為：', '["皮膚反映個人的生命歷史與獨特故事", "皮膚如同屏障，抵禦外力且堅不可摧", "皮膚如同螢幕，即時反映人們的情緒", "皮膚扮演生理與社會角色，意義特殊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00232', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「……看我，拿著甘蔗的樣子，像吹弄著一枝仙笛，一枝可口的牧歌，每 一節都是妙句。用春雨的祝福釀成，和南投芬芳的鄉土，必須細細地咀嚼， 讓一股甘冽的清泉，從最深的內陸，來澆遍我渴望的肺腑。冰箱卻冷冷地 宣布：已經，是最後一枝。但向北的高速公路，羊蹄甲，木棉花，發得正 艷的西螺站頭，還有一千枝，一萬枝——我的一千五喜美銀馬。躍躍在樓 下回答。」詩中最能看出作者無窮回味之盼望的是：', '["像是澆遍肺腑中的一股甘冽清泉", "如仙笛、牧歌所散發出來的滋味", "花朵爭艷的道路與躍躍欲發的車", "用春雨的祝福及鄉土的芬芳釀成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00233', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「我們似乎不該將桃花源固定在某一個地方，這樣可以留給生活在亂世， 又無山林可遁的人，一個遙望青山，仰觀白雲遐思的機會。是的，知識分 子胸中，都隱藏著一個桃花源，自有青山白雲，何必又另覓山林呢？」最 接近上文旨意的選項為：', '["隱居山林，方能見得青山白雲", "亂世動盪不安，人間勝地難求", "知識分子雖在亂世，仍欲實踐抱負", "真正理想之地存在於心，不須外求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00234', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「野柳的地層主要由傾斜的層狀沉積岩所組成，遠眺野柳岬時，它就像隻 烏龜般俯臥在海中，所以又稱為『野柳龜』。因海域險惡，經常發生船難。 因此民間傳說有烏龜精潛伏在海中作祟，玉皇大帝得知消息，便命仙女手 持寶劍下凡收妖。烏龜精中劍後元氣大傷，之後每當天候惡劣時，野柳岬 便會冒起一股白煙，村民看到便會說：『半死的野柳龜又在喘息了。』」 根據上文，下列敘述何者最適當？', '["烏龜精是玉皇大帝殺死的", "野柳岬的形成是由於花崗岩堆積", "傳說中野柳的煙是烏龜精的喘息", "「野柳」一名的來源因烏龜精而產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00235', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「我想到我已過的四十年中，大部分其實是被我浪費掉了的，我浪費生命 的原因，有的是為了滿足我的虛榮心，有的是為了討好世俗。就以我辛苦 讀學位的這件事來說，我是真為學問而去就讀的嗎？其中難道沒有為著想 『彌補』我教書生涯的不順遂、難道沒有打算在親友面前爭一口『氣』的 意思在嗎？如果有一點點不純粹，就如宋明儒所說的是在『搬弄光景』了。」 有關上文意涵的解說，下列敘述何者錯誤？', '["人不見得全是為了學問而努力讀書", "「搬弄光景」意指作學問華而不實", "學問有時亦是一種討好世俗的虛榮", "過度追求學問反而會導致自取其辱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00236', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「裝置藝術，是將整個空間當作一件作品，讓人深入體驗的藝術。」通過 下列對於藝術作品的描述，何者是裝置藝術？', '["用黏土塑形之後還會上釉藥，放進窯中燒之後，表面上便會出現繽紛的 色彩", "燒好後，趁金屬還很燙的時候拿出來。用加壓器把它壓扁，然後趁著溫 度還沒下降，再用大鐵鎚用力敲擊", "黑暗清冷的百貨公司裡，無數空瓶等距離排列在地板上，藍色燈光從斜 上方照射下來，空瓶映現出獨特的圖樣和粼粼波光，彷彿要沉入水中一 般，相當不可思議", "先把寫字的動作分解成上下、左右、前後三個部分，再分別記錄到三片 獨立的凸輪上，使它們連動，重現這些動作。凸輪的形狀是自己摸索的， 邊做邊想試了六百次以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00237', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在我們的文化裡，哪裡有『母女專屬時間』這個概念？這個社會向來談 的都是我們要給孩子相處的『品質時間』，陪伴孩子長大，什麼人談過我 們要給父母『品質時間』，陪伴他們老去？我在紐約咖啡館裡坐著的時候， 美君你正在高雄路竹的鄉下養豬，女兒出國深造，兩個弟弟大學還沒畢業， 你們仍然在勞動，為了下一代的教育。」下列選項，最符合上文主旨的是：', '["感念母親犧牲，才能讓自己出國深造", "母親養豬栽培子女，自己卻不及報恩", "不該讓母親長住鄉下，搬到都市才好", "母親一生辛勞，應陪伴她過晚年生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00238', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「如今這個世界，已經被我們自己弄得烏煙瘴氣、混亂不堪了。權力的爭 奪、武器的競賽、道德的墮落，累世不斷、緜延不已的仇恨與謀殺……太 多的負面狀況出現在我們周遭，做為一個有理想、有感知的人，活在今天， 是傷心的，但是，出以己身既蒙天地之愛而生為人，我們便應以愛還報世 界的使命感，以及對整體人類所懷抱的悲憫與大愛，仍願意抱持『知其不 可而為之』的態度去努力，去改善一點什麼。當然，我們並不是一無弱點 的人，但是，在真誠的面對每天的生活與工作中，我們得以愛提升自己， 同時也提升這個世界；在廣宇悠宙之間，我們要永遠懷著不死的理想，堅 定地相信——有一天，在那遙遠之處，所有的人類，終將以愛相遇。」下 列選項，何者最切合上文意旨？', '["世界混亂，但求以愛彌補缺憾", "人間有愛，我們都應該珍惜彼此的相遇", "天地不仁，理當彼此競爭才能進步提升", "世界既然不會改變，更要好好生活與工作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00239', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，關於上文，下列敘述何者較不適當？', '["提升自己也等同於改善世界", "要努力的原因是因為想把愛還諸天地", "傷心的原因是因為感受到自己的生活艱苦", "人類以愛相遇代表著人與人之間充滿愛與關懷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
